    for (int row = blockIdx.x; row < V; row += gridDim.x) {
        int scale_row = row >> 7;
        const uint8_t *row_ptr = a + (size_t)row * K;
        float sum = 0.0f;
        for (int col = tid; col < K; col += blockDim.x) {
            float s = scale_inv[scale_row * scale_cols + (col >> 7)];
            sum += tq_e4m3_to_float(row_ptr[col]) * s * x[col];
        }
