        cached = env ? atoi(env) : 1;
        if (cached != 2) cached = 1;
    }
    return cached;
}

static int qmma_sf_prefetch_distance(void) {
    static int cached = -1;
    if (cached < 0) {
        const char *env = getenv("TQ_QMMA_SF_PREFETCH_DISTANCE");
        cached = env ? atoi(env) : 0;
        if (cached < 0) cached = 0;
        if (cached > 16) cached = 16;
    }
    return cached;
